import styled from 'styled-components';
 
 export const Page = styled.div`
  min-height: 100vh;
  min-width: 100vw;
  display: flex;
  background-color: peachpuff;
  opacity: 0.6;
`;

export const Corridor = styled.img`
  padding: 1vh;
  height: 85.5vh;
`
